     1→/**
     2→ * Overlay Data Slice
     3→ *
     4→ * State management for canvas overlay panels: man-hours and drift analysis.
     5→ * These overlays provide actionable insights on top of the PM schedule canvas.
     6→ *
     7→ * @see specs/006-user-interface.md Section 6.4.3
     8→ */
     9→
    10→import { createSlice } from '@belt/tools';
    11→
    12→// =============================================================================
    13→// Bow-Wave Overlay Types
    14→// =============================================================================
    15→
    16→export type BowWaveRiskLevel = 'LOW' | 'MEDIUM' | 'HIGH' | 'CRITICAL';
    17→
    18→export interface QuarterlyLoad {
    19→  quarter: string;
    20→  year: number;
    21→  quarterNum: number;
    22→  pmCount: number;
    23→  totalHours: number;
    24→  capacityUtilizationPct: number;
    25→}
    26→
    27→export interface BowWavePeakPeriod {
    28→  startQuarter: string;
    29→  endQuarter: string;
    30→  averageLoad: number;
    31→  peakLoad: number;
    32→  riskLevel: BowWaveRiskLevel;
    33→}
    34→
    35→export interface BowWaveRecommendation {
    36→  type: 'ADVANCE_PM' | 'DEFER_PM' | 'ADD_CAPACITY' | 'SPREAD_WORKLOAD';
    37→  description: string;
    38→  impact: string;
    39→  priority: 'HIGH' | 'MEDIUM' | 'LOW';
    40→}
    41→
    42→export interface BowWaveOverlayData {
    43→  riskLevel: BowWaveRiskLevel;
    44→  riskScore: number; // 0-1 from strategic planner
    45→  planId: string | null;
    46→  planDate: string | null;
    47→  quarterlyLoads: QuarterlyLoad[];
    48→  peakPeriods: BowWavePeakPeriod[];
    49→  recommendations: BowWaveRecommendation[];
    50→  summary: {
    51→    totalPms: number;
    52→    firstHalfLoad: number;
    53→    secondHalfLoad: number;
    54→    loadImbalanceRatio: number;
    55→    affectedFleets: string[];
    56→  };
    57→}
    58→
    59→// =============================================================================
    60→// Man-Hour Overlay Types
    61→// =============================================================================
    62→
    63→export type ManhourStatus = 'OVERLOADED' | 'OPTIMAL' | 'UNDERUTILIZED';
    64→
    65→export interface ManhourAdjustment {
    66→  type: string;
    67→  hours: number;
    68→  status: string;
    69→}
    70→
    71→export interface DepotManhourData {
    72→  depotId: string;
    73→  depotCode: string;
    74→  requiredHours: number;
    75→  availableHours: number;
    76→  utilizationPct: number;
    77→  status: ManhourStatus;
    78→  adjustments: ManhourAdjustment[];
    79→}
    80→
    81→export interface ManhourWeekData {
    82→  weekStart: string;
    83→  depots: DepotManhourData[];
    84→}
    85→
    86→export interface ManhourOverlayData {
    87→  weeks: ManhourWeekData[];
    88→}
    89→
    90→// =============================================================================
    91→// Drift Overlay Types
    92→// =============================================================================
    93→
    94→export type DriftSeverity = 'GREEN' | 'YELLOW' | 'RED';
    95→
    96→export interface PmDrift {
    97→  pmId: string;
    98→  driftDays: number;
    99→}
   100→
   101→export interface TrainDriftData {
   102→  trainId: string;
   103→  trainNumber: string;
   104→  driftSeverity: DriftSeverity;
   105→  mileageDriftPct: number;
   106→  pmDrifts: PmDrift[];
   107→}
   108→
   109→export interface DriftOverlayData {
   110→  baselineId: string;
   111→  baselineName: string;
   112→  trains: TrainDriftData[];
   113→}
   114→
   115→export interface DriftRecommendation {
   116→  trainId: string;
   117→  trainNumber: string;
   118→  recommendation: 'REPLAN' | 'MONITOR' | 'OK';
   119→  reason: string;
   120→  priority: 'HIGH' | 'MEDIUM' | 'LOW';
   121→}
   122→
   123→// =============================================================================
   124→// Baseline Shadow Overlay Types
   125→// =============================================================================
   126→
   127→export type BaselinePmStatus = 'UNCHANGED' | 'MOVED' | 'ADDED' | 'REMOVED';
   128→
   129→export interface BaselinePmBlock {
   130→  pmId: string;
   131→  trainId: string;
   132→  trainNumber: string;
   133→  pmCode: string;
   134→  baselineDate: string;
   135→  currentDate: string | null;
   136→  driftDays: number;
   137→  status: BaselinePmStatus;
   138→  displayColor: string;
   139→}
   140→
   141→export interface BaselineShadowData {
   142→  baselineId: string;
   143→  baselineName: string;
   144→  baselineDate: string;
   145→  pmBlocks: BaselinePmBlock[];
   146→  summary: {
   147→    totalPms: number;
   148→    movedPms: number;
   149→    addedPms: number;
   150→    removedPms: number;
   151→    unchangedPms: number;
   152→    avgDriftDays: number;
   153→  };
   154→}
   155→
   156→// =============================================================================
   157→// Explanation Panel Types
   158→// =============================================================================
   159→
   160→import type {
   161→  ExplanationState,
   162→  ExplanationType,
   163→  PmScheduleExplanation,
   164→  RunAssignmentExplanation,
   165→} from '../../components/explanation/types';
   166→
   167→// =============================================================================
   168→// Overlay State
   169→// =============================================================================
   170→
   171→export interface OverlaySliceState {
   172→  // Bow-wave overlay
   173→  bowWaveData: BowWaveOverlayData | null;
   174→  bowWaveLoading: boolean;
   175→  bowWaveError: string | null;
   176→  bowWaveLastFetch: number | null;
   177→  bowWavePanelExpanded: boolean;
   178→  bowWaveSelectedQuarter: string | null;
   179→
   180→  // Man-hour overlay
   181→  manhourData: ManhourOverlayData | null;
   182→  manhourLoading: boolean;
   183→  manhourError: string | null;
   184→  manhourLastFetch: number | null;
   185→  manhourWeeks: number;
   186→  manhourDepotFilter: string | null;
   187→  manhourExpandedWeeks: string[];
   188→
   189→  // Drift overlay
   190→  driftData: DriftOverlayData | null;
   191→  driftLoading: boolean;
   192→  driftError: string | null;
   193→  driftLastFetch: number | null;
   194→  driftBaselineId: string | null;
   195→  driftSeverityFilter: DriftSeverity | null;
   196→  driftExpandedTrains: string[];
   197→  driftRecommendations: DriftRecommendation[];
   198→
   199→  // Baseline shadow overlay
   200→  baselineShadowData: BaselineShadowData | null;
   201→  baselineShadowLoading: boolean;
   202→  baselineShadowError: string | null;
   203→  baselineShadowLastFetch: number | null;
   204→  baselineShadowBaselineId: string | null;
   205→  baselineShadowStatusFilter: BaselinePmStatus | null;
   206→
   207→  // Panel state
   208→  manhourPanelExpanded: boolean;
   209→  driftPanelExpanded: boolean;
   210→  baselineShadowPanelExpanded: boolean;
   211→
   212→  // Explanation panel (spec 006 section 6.6)
   213→  explanation: ExplanationState;
   214→
   215→  // Chaos Monkey (demo feature)
   216→  chaosMonkeyEnabled: boolean;
   217→  chaosMonkeyConfig: {
   218→    delayMonths: number;
   219→    disruptionStartMonth: number;
   220→    affectRate: number;
   221→  };
   222→
   223→  [key: string]: unknown;
   224→}
   225→
   226→const initialOverlayState: OverlaySliceState = {
   227→  // Bow-wave overlay
   228→  bowWaveData: null,
   229→  bowWaveLoading: false,
   230→  bowWaveError: null,
   231→  bowWaveLastFetch: null,
   232→  bowWavePanelExpanded: true,
   233→  bowWaveSelectedQuarter: null,
   234→
   235→  // Man-hour overlay
   236→  manhourData: null,
   237→  manhourLoading: false,
   238→  manhourError: null,
   239→  manhourLastFetch: null,
   240→  manhourWeeks: 12,
   241→  manhourDepotFilter: null,
   242→  manhourExpandedWeeks: [],
   243→
   244→  // Drift overlay
   245→  driftData: null,
   246→  driftLoading: false,
   247→  driftError: null,
   248→  driftLastFetch: null,
   249→  driftBaselineId: null,
   250→  driftSeverityFilter: null,
   251→  driftExpandedTrains: [],
   252→  driftRecommendations: [],
   253→
   254→  // Baseline shadow overlay
   255→  baselineShadowData: null,
   256→  baselineShadowLoading: false,
   257→  baselineShadowError: null,
   258→  baselineShadowLastFetch: null,
   259→  baselineShadowBaselineId: null,
   260→  baselineShadowStatusFilter: null,
   261→
   262→  // Panel state
   263→  manhourPanelExpanded: true,
   264→  driftPanelExpanded: true,
   265→  baselineShadowPanelExpanded: true,
   266→
   267→  // Explanation panel (spec 006 section 6.6)
   268→  explanation: {
   269→    isVisible: false,
   270→    type: null,
   271→    pmExplanation: null,
   272→    runAssignmentExplanation: null,
   273→    loading: false,
   274→    error: null,
   275→    selectedPmId: null,
   276→    selectedAssignmentId: null,
   277→  },
   278→
   279→  // Chaos Monkey (demo feature)
   280→  chaosMonkeyEnabled: false,
   281→  chaosMonkeyConfig: {
   282→    delayMonths: 3,
   283→    disruptionStartMonth: 6,
   284→    affectRate: 0.7,
   285→  },
   286→};
   287→
   288→export const overlaySlice = createSlice({
   289→  id: 'overlay',
   290→  initial: initialOverlayState,
   291→  cache: { policy: 'session' },
   292→  reducers: {
   293→    // ==========================================================================
   294→    // Bow-Wave Overlay Reducers
   295→    // ==========================================================================
   296→
   297→    setBowWaveLoading: (s, loading: boolean) => {
   298→      const state = s as OverlaySliceState;
   299→      state.bowWaveLoading = loading;
   300→    },
   301→
   302→    setBowWaveData: (s, data: BowWaveOverlayData) => {
   303→      const state = s as OverlaySliceState;
   304→      state.bowWaveData = data;
   305→      state.bowWaveLoading = false;
   306→      state.bowWaveError = null;
   307→      state.bowWaveLastFetch = Date.now();
   308→    },
   309→
   310→    setBowWaveError: (s, error: string) => {
   311→      const state = s as OverlaySliceState;
   312→      state.bowWaveError = error;
   313→      state.bowWaveLoading = false;
   314→    },
   315→
   316→    clearBowWaveData: (s) => {
   317→      const state = s as OverlaySliceState;
   318→      state.bowWaveData = null;
   319→      state.bowWaveError = null;
   320→      state.bowWaveLastFetch = null;
   321→      state.bowWaveSelectedQuarter = null;
   322→    },
   323→
   324→    setBowWaveSelectedQuarter: (s, quarter: string | null) => {
   325→      const state = s as OverlaySliceState;
   326→      state.bowWaveSelectedQuarter = quarter;
   327→    },
   328→
   329→    toggleBowWavePanel: (s) => {
   330→      const state = s as OverlaySliceState;
   331→      state.bowWavePanelExpanded = !state.bowWavePanelExpanded;
   332→    },
   333→
   334→    // ==========================================================================
   335→    // Man-hour Overlay Reducers
   336→    // ==========================================================================
   337→
   338→    setManhourLoading: (s, loading: boolean) => {
   339→      const state = s as OverlaySliceState;
   340→      state.manhourLoading = loading;
   341→    },
   342→
   343→    setManhourData: (s, data: ManhourOverlayData) => {
   344→      const state = s as OverlaySliceState;
   345→      state.manhourData = data;
   346→      state.manhourLoading = false;
   347→      state.manhourError = null;
   348→      state.manhourLastFetch = Date.now();
   349→    },
   350→
   351→    setManhourError: (s, error: string) => {
   352→      const state = s as OverlaySliceState;
   353→      state.manhourError = error;
   354→      state.manhourLoading = false;
   355→    },
   356→
   357→    clearManhourData: (s) => {
   358→      const state = s as OverlaySliceState;
   359→      state.manhourData = null;
   360→      state.manhourError = null;
   361→      state.manhourLastFetch = null;
   362→    },
   363→
   364→    setManhourWeeks: (s, weeks: number) => {
   365→      const state = s as OverlaySliceState;
   366→      state.manhourWeeks = weeks;
   367→    },
   368→
   369→    setManhourDepotFilter: (s, depotId: string | null) => {
   370→      const state = s as OverlaySliceState;
   371→      state.manhourDepotFilter = depotId;
   372→    },
   373→
   374→    expandManhourWeek: (s, weekStart: string) => {
   375→      const state = s as OverlaySliceState;
   376→      if (!state.manhourExpandedWeeks.includes(weekStart)) {
   377→        state.manhourExpandedWeeks.push(weekStart);
   378→      }
   379→    },
   380→
   381→    collapseManhourWeek: (s, weekStart: string) => {
   382→      const state = s as OverlaySliceState;
   383→      state.manhourExpandedWeeks = state.manhourExpandedWeeks.filter(w => w !== weekStart);
   384→    },
   385→
   386→    toggleManhourWeek: (s, weekStart: string) => {
   387→      const state = s as OverlaySliceState;
   388→      if (state.manhourExpandedWeeks.includes(weekStart)) {
   389→        state.manhourExpandedWeeks = state.manhourExpandedWeeks.filter(w => w !== weekStart);
   390→      } else {
   391→        state.manhourExpandedWeeks.push(weekStart);
   392→      }
   393→    },
   394→
   395→    toggleManhourPanel: (s) => {
   396→      const state = s as OverlaySliceState;
   397→      state.manhourPanelExpanded = !state.manhourPanelExpanded;
   398→    },
   399→
   400→    // ==========================================================================
   401→    // Drift Overlay Reducers
   402→    // ==========================================================================
   403→
   404→    setDriftLoading: (s, loading: boolean) => {
   405→      const state = s as OverlaySliceState;
   406→      state.driftLoading = loading;
   407→    },
   408→
   409→    setDriftData: (s, data: DriftOverlayData) => {
   410→      const state = s as OverlaySliceState;
   411→      state.driftData = data;
   412→      state.driftLoading = false;
   413→      state.driftError = null;
   414→      state.driftLastFetch = Date.now();
   415→
   416→      // Generate recommendations based on drift data
   417→      state.driftRecommendations = data.trains
   418→        .filter(t => t.driftSeverity !== 'GREEN')
   419→        .map(train => ({
   420→          trainId: train.trainId,
   421→          trainNumber: train.trainNumber,
   422→          recommendation: train.driftSeverity === 'RED' ? 'REPLAN' as const : 'MONITOR' as const,
   423→          reason: train.driftSeverity === 'RED'
   424→            ? `Mileage drift of ${Math.abs(train.mileageDriftPct).toFixed(1)}% exceeds threshold`
   425→            : `Mileage drift approaching threshold at ${Math.abs(train.mileageDriftPct).toFixed(1)}%`,
   426→          priority: train.driftSeverity === 'RED' ? 'HIGH' as const : 'MEDIUM' as const,
   427→        }));
   428→    },
   429→
   430→    setDriftError: (s, error: string) => {
   431→      const state = s as OverlaySliceState;
   432→      state.driftError = error;
   433→      state.driftLoading = false;
   434→    },
   435→
   436→    clearDriftData: (s) => {
   437→      const state = s as OverlaySliceState;
   438→      state.driftData = null;
   439→      state.driftError = null;
   440→      state.driftLastFetch = null;
   441→      state.driftRecommendations = [];
   442→    },
   443→
   444→    setDriftBaselineId: (s, baselineId: string | null) => {
   445→      const state = s as OverlaySliceState;
   446→      state.driftBaselineId = baselineId;
   447→    },
   448→
   449→    setDriftSeverityFilter: (s, severity: DriftSeverity | null) => {
   450→      const state = s as OverlaySliceState;
   451→      state.driftSeverityFilter = severity;
   452→    },
   453→
   454→    expandDriftTrain: (s, trainId: string) => {
   455→      const state = s as OverlaySliceState;
   456→      if (!state.driftExpandedTrains.includes(trainId)) {
   457→        state.driftExpandedTrains.push(trainId);
   458→      }
   459→    },
   460→
   461→    collapseDriftTrain: (s, trainId: string) => {
   462→      const state = s as OverlaySliceState;
   463→      state.driftExpandedTrains = state.driftExpandedTrains.filter(t => t !== trainId);
   464→    },
   465→
   466→    toggleDriftTrain: (s, trainId: string) => {
   467→      const state = s as OverlaySliceState;
   468→      if (state.driftExpandedTrains.includes(trainId)) {
   469→        state.driftExpandedTrains = state.driftExpandedTrains.filter(t => t !== trainId);
   470→      } else {
   471→        state.driftExpandedTrains.push(trainId);
   472→      }
   473→    },
   474→
   475→    toggleDriftPanel: (s) => {
   476→      const state = s as OverlaySliceState;
   477→      state.driftPanelExpanded = !state.driftPanelExpanded;
   478→    },
   479→
   480→    // ==========================================================================
   481→    // Baseline Shadow Overlay Reducers
   482→    // ==========================================================================
   483→
   484→    setBaselineShadowLoading: (s, loading: boolean) => {
   485→      const state = s as OverlaySliceState;
   486→      state.baselineShadowLoading = loading;
   487→    },
   488→
   489→    setBaselineShadowData: (s, data: BaselineShadowData) => {
   490→      const state = s as OverlaySliceState;
   491→      state.baselineShadowData = data;
   492→      state.baselineShadowLoading = false;
   493→      state.baselineShadowError = null;
   494→      state.baselineShadowLastFetch = Date.now();
   495→    },
   496→
   497→    setBaselineShadowError: (s, error: string) => {
   498→      const state = s as OverlaySliceState;
   499→      state.baselineShadowError = error;
   500→      state.baselineShadowLoading = false;
   501→    },
   502→
   503→    clearBaselineShadowData: (s) => {
   504→      const state = s as OverlaySliceState;
   505→      state.baselineShadowData = null;
   506→      state.baselineShadowError = null;
   507→      state.baselineShadowLastFetch = null;
   508→    },
   509→
   510→    setBaselineShadowBaselineId: (s, baselineId: string | null) => {
   511→      const state = s as OverlaySliceState;
   512→      state.baselineShadowBaselineId = baselineId;
   513→    },
   514→
   515→    setBaselineShadowStatusFilter: (s, status: BaselinePmStatus | null) => {
   516→      const state = s as OverlaySliceState;
   517→      state.baselineShadowStatusFilter = status;
   518→    },
   519→
   520→    toggleBaselineShadowPanel: (s) => {
   521→      const state = s as OverlaySliceState;
   522→      state.baselineShadowPanelExpanded = !state.baselineShadowPanelExpanded;
   523→    },
   524→
   525→    // ==========================================================================
   526→    // Chaos Monkey Reducers (Demo Feature)
   527→    // ==========================================================================
   528→
   529→    toggleChaosMonkey: (s) => {
   530→      const state = s as OverlaySliceState;
   531→      state.chaosMonkeyEnabled = !state.chaosMonkeyEnabled;
   532→      // Clear bow-wave data to trigger reload with new state
   533→      state.bowWaveData = null;
   534→      state.bowWaveLastFetch = null;
   535→    },
   536→
   537→    setChaosMonkeyEnabled: (s, enabled: boolean) => {
   538→      const state = s as OverlaySliceState;
   539→      state.chaosMonkeyEnabled = enabled;
   540→      // Clear bow-wave data to trigger reload with new state
   541→      state.bowWaveData = null;
   542→      state.bowWaveLastFetch = null;
   543→    },
   544→
   545→    setChaosMonkeyConfig: (
   546→      s,
   547→      config: Partial<{ delayMonths: number; disruptionStartMonth: number; affectRate: number }>
   548→    ) => {
   549→      const state = s as OverlaySliceState;
   550→      state.chaosMonkeyConfig = { ...state.chaosMonkeyConfig, ...config };
   551→      // Clear bow-wave data to trigger reload with new state
   552→      if (state.chaosMonkeyEnabled) {
   553→        state.bowWaveData = null;
   554→        state.bowWaveLastFetch = null;
   555→      }
   556→    },
   557→
   558→    // ==========================================================================
   559→    // Explanation Panel Reducers (spec 006 section 6.6)
   560→    // ==========================================================================
   561→
   562→    showExplanationPanel: (s) => {
   563→      const state = s as OverlaySliceState;
   564→      state.explanation.isVisible = true;
   565→    },
   566→
   567→    hideExplanationPanel: (s) => {
   568→      const state = s as OverlaySliceState;
   569→      state.explanation.isVisible = false;
   570→    },
   571→
   572→    toggleExplanationPanel: (s) => {
   573→      const state = s as OverlaySliceState;
   574→      state.explanation.isVisible = !state.explanation.isVisible;
   575→    },
   576→
   577→    setExplanationType: (s, type: ExplanationType) => {
   578→      const state = s as OverlaySliceState;
   579→      state.explanation.type = type;
   580→    },
   581→
   582→    setExplanationLoading: (s, loading: boolean) => {
   583→      const state = s as OverlaySliceState;
   584→      state.explanation.loading = loading;
   585→    },
   586→
   587→    setExplanationError: (s, error: string | null) => {
   588→      const state = s as OverlaySliceState;
   589→      state.explanation.error = error;
   590→      state.explanation.loading = false;
   591→    },
   592→
   593→    setPmExplanation: (s, explanation: PmScheduleExplanation | null) => {
   594→      const state = s as OverlaySliceState;
   595→      state.explanation.pmExplanation = explanation;
   596→      state.explanation.type = 'pm';
   597→      state.explanation.loading = false;
   598→      state.explanation.error = null;
   599→      if (explanation) {
   600→        state.explanation.selectedPmId = explanation.pmId;
   601→      }
   602→    },
   603→
   604→    setRunAssignmentExplanation: (s, explanation: RunAssignmentExplanation | null) => {
   605→      const state = s as OverlaySliceState;
   606→      state.explanation.runAssignmentExplanation = explanation;
   607→      state.explanation.type = 'runAssignment';
   608→      state.explanation.loading = false;
   609→      state.explanation.error = null;
   610→      if (explanation) {
   611→        state.explanation.selectedAssignmentId = explanation.assignmentId;
   612→      }
   613→    },
   614→
   615→    selectPmForExplanation: (s, pmId: string) => {
   616→      const state = s as OverlaySliceState;
   617→      state.explanation.selectedPmId = pmId;
   618→      state.explanation.type = 'pm';
   619→      state.explanation.isVisible = true;
   620→      state.explanation.loading = true;
   621→    },
   622→
   623→    selectAssignmentForExplanation: (s, assignmentId: string) => {
   624→      const state = s as OverlaySliceState;
   625→      state.explanation.selectedAssignmentId = assignmentId;
   626→      state.explanation.type = 'runAssignment';
   627→      state.explanation.isVisible = true;
   628→      state.explanation.loading = true;
   629→    },
   630→
   631→    clearExplanation: (s) => {
   632→      const state = s as OverlaySliceState;
   633→      state.explanation = {
   634→        isVisible: false,
   635→        type: null,
   636→        pmExplanation: null,
   637→        runAssignmentExplanation: null,
   638→        loading: false,
   639→        error: null,
   640→        selectedPmId: null,
   641→        selectedAssignmentId: null,
   642→      };
   643→    },
   644→
   645→    /** For integration with modals from explanation panel */
   646→    openModal: (s, payload: { type: string; data?: Record<string, unknown> }) => {
   647→      // This is a pass-through to trigger modal opening from UI slice
