   682→    setManhourError: (error: string) => void;
   683→  },
   684→  options: { baseUrl?: string; weeks?: number; depotId?: string } = {}
   685→): Promise<void> {
   686→  const { baseUrl = '/api/v1', weeks = 12, depotId } = options;
   687→
   688→  dispatch.setManhourLoading(true);
   689→
   690→  const params = new URLSearchParams();
   691→  params.set('weeks', String(weeks));
   692→  if (depotId) {
   693→    params.set('depotId', depotId);
   694→  }
   695→
   696→  try {
   697→    const response = await fetch(`${baseUrl}/canvas/manhour-overlay?${params}`);
   698→
   699→    if (!response.ok) {
