   701→    }
   702→
   703→    const json = await response.json() as { data: ManhourOverlayData };
   704→    dispatch.setManhourData(json.data);
   705→  } catch (error) {
   706→    const message = error instanceof Error ? error.message : 'Unknown error';
   707→    dispatch.setManhourError(message);
   708→  }
   709→}
