   750→/**
   751→ * Get filtered man-hour weeks based on depot filter
   752→ */
   753→export function selectFilteredManhourWeeks(state: OverlaySliceState): ManhourWeekData[] {
   754→  if (!state.manhourData) return [];
   755→
   756→  if (!state.manhourDepotFilter) {
   757→    return state.manhourData.weeks;
   758→  }
   759→
   760→  return state.manhourData.weeks.map(week => ({
   761→    ...week,
   762→    depots: week.depots.filter(d => d.depotId === state.manhourDepotFilter),
   763→  }));
   764→}
   765→
   766→/**
   767→ * Get weeks with overloaded status
   768→ */
   769→export function selectOverloadedWeeks(state: OverlaySliceState): ManhourWeekData[] {
   770→  if (!state.manhourData) return [];
   771→
   772→  return state.manhourData.weeks.filter(week =>
   773→    week.depots.some(d => d.status === 'OVERLOADED')
   774→  );
   775→}
