   777→/**
   778→ * Get total overloaded hours across all weeks
   779→ */
   780→export function selectTotalOverloadedHours(state: OverlaySliceState): number {
   781→  if (!state.manhourData) return 0;
   782→
   783→  return state.manhourData.weeks.reduce((total, week) => {
   784→    return total + week.depots.reduce((weekTotal, depot) => {
   785→      if (depot.status === 'OVERLOADED') {
   786→        return weekTotal + (depot.requiredHours - depot.availableHours);
   787→      }
   788→      return weekTotal;
   789→    }, 0);
   790→  }, 0);
   791→}
