  const { baseUrl = '/api/v1', assignmentId } = options;

  dispatch.setExplanationLoading(true);

  try {
    const response = await fetch(`${baseUrl}/run-assignments/${assignmentId}/explanation`);

    if (!response.ok) {
      throw new Error(`Failed to fetch run assignment explanation: ${response.status}`);
    }

    const json = await response.json() as { data: RunAssignmentExplanation };
    dispatch.setRunAssignmentExplanation(json.data);
  } catch (error) {
    const message = error instanceof Error ? error.message : 'Unknown error';
    dispatch.setExplanationError(message);
  }
}

// =============================================================================
// Explanation Panel Selectors
// =============================================================================

/**
 * Check if explanation panel is visible
 */
export function isExplanationPanelVisible(state: OverlaySliceState): boolean {
  return state.explanation.isVisible;
}

/**
 * Get current explanation type
 */
export function selectExplanationType(state: OverlaySliceState): ExplanationType {
  return state.explanation.type;
}

/**
 * Get PM explanation data
 */
export function selectPmExplanation(state: OverlaySliceState): PmScheduleExplanation | null {
  return state.explanation.pmExplanation;
}

/**
 * Get run assignment explanation data
 */
export function selectRunAssignmentExplanation(state: OverlaySliceState): RunAssignmentExplanation | null {
  return state.explanation.runAssignmentExplanation;
}

/**
 * Check if explanation is loading
 */
export function isExplanationLoading(state: OverlaySliceState): boolean {
  return state.explanation.loading;
}

/**
 * Get explanation error
 */
export function selectExplanationError(state: OverlaySliceState): string | null {
  return state.explanation.error;
}

