   401→
   402→interface PmBlockRectProps {
   403→  pm: PmBlock;
   404→  x: number;
   405→  y: number;
   406→  width: number;
   407→  isSelected: boolean;
   408→  isDragging?: boolean;
   409→  dragValidation?: DragValidationState | null;
   410→  onHover?: (pm: PmBlock | null) => void;
   411→  onClick?: (pmId: string) => void;
   412→  onDragStart?: (pmId: string, sourceDate: string) => void;
   413→  onDragMove?: (pmId: string, targetDate: string) => void;
   414→  onDragEnd?: (pmId: string, newDate: string) => void;
